- Types (`packages/core/src/types.ts`):
  ```ts
  interface LlmRequest { messages: ChatMessage[]; tools?: ToolDescriptor[] }
  interface LlmResponse { assistantMessage: ChatMessage; toolCalls: ToolCall[] }
  interface ChatMessage { role: 'user'|'assistant'|'system'; content: string }
  interface ToolCall { id: string; name: string; input: unknown }
  interface ToolDescriptor { name: string; description?: string }
  ```
  Important constraint: `ChatMessage.content` is a plain string, not the Anthropic content-block array. You must convert in both directions.
- SDK version to pin: `@anthropic-ai/sdk@0.90.0` (EXACT, no `^` or `~`). Already confirmed no pre/post/prepare install scripts.
- v1 reference code at `~/dev/ai/ax/src/providers/anthropic.ts` — look at auth + request shape only; skip orchestration.

## Security requirements (re-read CLAUDE.md invariant #5)

1. **`ANTHROPIC_API_KEY` handling:**
   - Read from `process.env.ANTHROPIC_API_KEY` at plugin **init time**, not per-call.
   - If missing → throw `PluginError({ code: 'init-failed', plugin: '@ax/llm-anthropic', message: 'ANTHROPIC_API_KEY env var not set' })`. No fallback, no "empty string" silently.
   - Key must NEVER appear in error messages, log output, or `LlmResponse` payloads. If the SDK throws a 401, surface it as `PluginError({ code: 'unknown', message: 'anthropic API error' })` or similar generic text — do NOT include the SDK error's full body or headers if they might contain echoed auth headers.
   - Do NOT forward the API key to anywhere else in the system (hooks, storage, children).

2. **Untrusted SDK response handling:**
   - Never `eval`, `Function(...)`, or template-interpolate any SDK response field.
   - When mapping `content: [{ type: 'tool_use', input: {...} }]` → `ToolCall.input`, pass through as-is (it's `unknown` in the type). The tool plugins do their own Zod validation.

## What to build

### Scaffold — `packages/llm-anthropic/`

- `package.json` — name `@ax/llm-anthropic`, type module, workspace dep on `@ax/core`. Add `"@anthropic-ai/sdk": "0.90.0"` (EXACT — if you write `^0.90.0` you are wrong). DevDeps mirror `@ax/llm-mock`.
- `tsconfig.json` — references `../core`.
- `vitest.config.ts` — broadened pattern.
- `src/index.ts` — `export * from './plugin.js';`
- `src/plugin.ts`
- `src/mapping.ts` — message conversion helpers (so they're testable standalone).
- `src/__tests__/mapping.test.ts`
- `src/__tests__/plugin.test.ts`
- `SECURITY.md`
- `scripts/smoke.ts` (manual real-network test, NOT in CI).

Add `{ "path": "packages/llm-anthropic" }` to root `tsconfig.json` references.

### Config

The plugin should accept config via the `init({ config })` parameter. Shape:
```ts
interface AnthropicPluginConfig {
  model?: string;   // default 'claude-sonnet-4-5'
  maxTokens?: number; // default 4096
}
```

Default model: use `'claude-sonnet-4-5'` (widely available). Do not hardcode `claude-sonnet-4-6` unless you are certain it exists at the API level — using a nonexistent model surfaces as a confusing 404.

### Mapping helpers (`src/mapping.ts`)

```ts
import type { ChatMessage, ToolCall } from '@ax/core';
import type Anthropic from '@anthropic-ai/sdk';

// Convert ax ChatMessage[] → Anthropic's message[] form.
// Drop role === 'system' messages and concatenate them into a system prompt (return { system, messages }).
export function toAnthropicMessages(msgs: ChatMessage[]): {
  system: string | undefined;
  messages: { role: 'user' | 'assistant'; content: string }[];
};

// Convert Anthropic Messages.Message response → ax LlmResponse shape.
// Aggregates text blocks into a single assistant content string; pulls tool_use blocks into ToolCall[].
export function fromAnthropicMessage(resp: Anthropic.Messages.Message): {
  assistantMessage: ChatMessage;
  toolCalls: ToolCall[];
};
```

**Tests (`mapping.test.ts`):**
1. `toAnthropicMessages`: user-only → no system, messages pass through.
2. `toAnthropicMessages`: mixed with a system message → system string is set, system message removed from messages array.
3. `toAnthropicMessages`: multiple system messages concatenated (newline-joined).
4. `fromAnthropicMessage`: text-only content → `assistantMessage.content` equals the text, `toolCalls === []`.
5. `fromAnthropicMessage`: tool_use block → `toolCalls[0] === { id, name, input }`, `assistantMessage.content` is any leading text (or empty string).
6. `fromAnthropicMessage`: mixed text + tool_use → both captured.

### Plugin (`src/plugin.ts`)

```ts
import Anthropic from '@anthropic-ai/sdk';
import { PluginError, type LlmRequest, type LlmResponse, type Plugin, type ChatContext } from '@ax/core';
import { toAnthropicMessages, fromAnthropicMessage } from './mapping.js';

const PLUGIN_NAME = '@ax/llm-anthropic';
const DEFAULT_MODEL = 'claude-sonnet-4-5';
const DEFAULT_MAX_TOKENS = 4096;

export interface AnthropicPluginConfig {
  model?: string;
  maxTokens?: number;
  // Test-only hook. Production code paths use the real SDK.
  client?: Pick<Anthropic, 'messages'>;
}

export function llmAnthropicPlugin(): Plugin {
  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: ['llm:call'],
      calls: [],
      subscribes: [],
    },
    init({ bus, config }) {
      const cfg = (config as AnthropicPluginConfig | undefined) ?? {};
      const client = cfg.client ?? new Anthropic({ apiKey: requireApiKey() });
      const model = cfg.model ?? DEFAULT_MODEL;
      const maxTokens = cfg.maxTokens ?? DEFAULT_MAX_TOKENS;
      bus.registerService<LlmRequest, LlmResponse>(
        'llm:call',
        PLUGIN_NAME,
        async (_ctx: ChatContext, input) => call(client, model, maxTokens, input),
      );
    },
  };
}

function requireApiKey(): string {
  const key = process.env.ANTHROPIC_API_KEY;
  if (!key || key.length === 0) {
    throw new PluginError({
      code: 'init-failed',
      plugin: PLUGIN_NAME,
      message: 'ANTHROPIC_API_KEY env var not set',
    });
  }
  return key;
}

async function call(
  client: Pick<Anthropic, 'messages'>,
  model: string,
  maxTokens: number,
  input: LlmRequest,
): Promise<LlmResponse> {
  const { system, messages } = toAnthropicMessages(input.messages);
  try {
    const resp = await client.messages.create({
      model,
      max_tokens: maxTokens,
      ...(system !== undefined ? { system } : {}),
      messages,
      ...(input.tools && input.tools.length > 0 ? { tools: input.tools.map(t => ({ name: t.name, description: t.description ?? '', input_schema: { type: 'object' as const, properties: {} } })) } : {}),
    });
    return fromAnthropicMessage(resp);
  } catch (err) {
    // Do not forward SDK error details (may include headers, request bodies, API key echoes).
    throw new PluginError({
      code: 'unknown',
      plugin: PLUGIN_NAME,
      hookName: 'llm:call',
      message: 'anthropic API error',
      cause: err,
    });
  }
