import Anthropic from '@anthropic-ai/sdk';
import { PluginError, type LlmRequest, type LlmResponse, type Plugin, type ChatContext } from '@ax/core';
import { toAnthropicMessages, fromAnthropicMessage } from './mapping.js';

const PLUGIN_NAME = '@ax/llm-anthropic';
const DEFAULT_MODEL = 'claude-sonnet-4-5';
const DEFAULT_MAX_TOKENS = 4096;

export interface AnthropicPluginConfig {
  model?: string;
  maxTokens?: number;
  // Test-only hook. Production code paths use the real SDK.
  client?: Pick<Anthropic, 'messages'>;
}

export function llmAnthropicPlugin(): Plugin {
  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: ['llm:call'],
      calls: [],
      subscribes: [],
    },
    init({ bus, config }) {
      const cfg = (config as AnthropicPluginConfig | undefined) ?? {};
      const client = cfg.client ?? new Anthropic({ apiKey: requireApiKey() });
      const model = cfg.model ?? DEFAULT_MODEL;
      const maxTokens = cfg.maxTokens ?? DEFAULT_MAX_TOKENS;
      bus.registerService<LlmRequest, LlmResponse>(
        'llm:call',
        PLUGIN_NAME,
        async (_ctx: ChatContext, input) => call(client, model, maxTokens, input),
