    role: 'assistant',
    model: 'fixture-model',
    stop_reason: 'tool_use',
    stop_sequence: null,
    usage: { input_tokens: 0, output_tokens: 0 },
    content: [
      { type: 'tool_use', id: 'tool_1', name: 'bash', input: { command: 'echo fixture-hello' } },
    ],
  },
  // Turn 2: LLM concludes after seeing the tool output
  {
    id: 'msg_2',
    type: 'message',
    role: 'assistant',
    model: 'fixture-model',
    stop_reason: 'end_turn',
